import{_ as a,c as i,o as e,aj as s}from"./chunks/framework.CLcCQpUA.js";const u=JSON.parse('{"title":"✒️ 其他网站的扩展开发指南","description":"","frontmatter":{},"headers":[],"relativePath":"dev/dev_spider.md","filePath":"dev/dev_spider.md"}'),t={name:"dev/dev_spider.md"},o=s('<h1 id="✒️-其他网站的扩展开发指南" tabindex="-1">✒️ 其他网站的扩展开发指南 <a class="header-anchor" href="#✒️-其他网站的扩展开发指南" aria-label="Permalink to &quot;✒️ 其他网站的扩展开发指南&quot;">​</a></h1><p>Website crawler develope guide</p><p>基于 <code>Scrapy</code><br> 需切换到 <strong>下一个版本</strong> Minor 开发分支，PR 时提交到此分支</p><h2 id="开发步骤" tabindex="-1">开发步骤 <a class="header-anchor" href="#开发步骤" aria-label="Permalink to &quot;开发步骤&quot;">​</a></h2><h3 id="_1-爬虫代码" tabindex="-1">1. 爬虫代码 <a class="header-anchor" href="#_1-爬虫代码" aria-label="Permalink to &quot;1. 爬虫代码&quot;">​</a></h3><p>以 wnacg 为例</p><p><a href="https://github.com/jasoneri/ComicGUISpider/blob/GUI/ComicSpider/spiders/wnacg.py" target="_blank" rel="noreferrer">scrapy爬虫类: <code>WnacgSpider</code></a><br><a href="https://github.com/jasoneri/ComicGUISpider/blob/GUI/utils/website/ins.py" target="_blank" rel="noreferrer">xpath解析类: <code>WnacgUtils</code></a></p><h4 id="wnacgspider" tabindex="-1">WnacgSpider <a class="header-anchor" href="#wnacgspider" aria-label="Permalink to &quot;WnacgSpider&quot;">​</a></h4><p> ✅ name: 爬虫名字，取目标网站域名的部分或标题，与分支名相同<br>  ✅ domain: 目标网站域名<br>  ✅ search_url_head: 搜索页url(去掉关键词)，大部分网站都是以get形式直出的</p><h5 id="类方法" tabindex="-1">类方法 <a class="header-anchor" href="#类方法" aria-label="Permalink to &quot;类方法&quot;">​</a></h5><p> 🔳 @property search: 生成第一个请求的连接，可结合<code>mappings</code>进行复杂输入的转换<br>  🔳 start_requests: 发出第一个请求，可在此进行<code>search</code>实现不了 或 不合其逻辑的操作<br>  🔳 parse_fin_page: (一跳页面不需要，二跳页面必须) 章节页面 &gt; 直接获取该章节的全页</p><h5 id="常用方法" tabindex="-1">常用方法 <a class="header-anchor" href="#常用方法" aria-label="Permalink to &quot;常用方法&quot;">​</a></h5><ul><li>self.say: 能将字符串(可使用部分html标签格式)打印在gui上</li></ul><h4 id="wnacgutils" tabindex="-1">WnacgUtils <a class="header-anchor" href="#wnacgutils" aria-label="Permalink to &quot;WnacgUtils&quot;">​</a></h4><p>常规漫与🔞继承基类不同</p><h5 id="类属性-utils" tabindex="-1">类属性(Utils) <a class="header-anchor" href="#类属性-utils" aria-label="Permalink to &quot;类属性(Utils)&quot;">​</a></h5><p> ✅ name: 同爬虫名字<br>  ✅ uuid_regex: 将 作品id 从作品 预览url 中抽取的正则表达式<br>  🔳 headers: 通用请求头<br>  🔳 book_hea: 读剪贴板功能使用的请求头<br>  🔳 book_url_regex: 读剪贴板功能使用所对应当前网站抽取 作品id 的正则表达式</p><h5 id="类方法-utils" tabindex="-1">类方法(Utils) <a class="header-anchor" href="#类方法-utils" aria-label="Permalink to &quot;类方法(Utils)&quot;">​</a></h5><p> ✅ parse_search_item: 解析搜索页 xpath -&gt; BookInfo<br>  🔳 parse_book: 读剪贴板功能 xpath 等解析作品页 -&gt; BookInfo<br>  🔳 parse_search: 聚合搜索 xpath 等解析搜索页 -&gt; List[BookInfo]<br>  🔳 parse_publish_: 解析发布页<br>  🔳 test_index: 测试网络环境能否访问当前网站</p><div class="tip custom-block"><p class="custom-block-title">最后需要在 spider_utils_map 加上对应的 Utils</p></div><h3 id="_2-其他代码" tabindex="-1">2. 其他代码 <a class="header-anchor" href="#_2-其他代码" aria-label="Permalink to &quot;2. 其他代码&quot;">​</a></h3><h4 id="variables-init-py" tabindex="-1"><a href="https://github.com/jasoneri/ComicGUISpider/blob/GUI/variables/__init__.py" target="_blank" rel="noreferrer"><code>variables/__init__.py</code></a> <a class="header-anchor" href="#variables-init-py" aria-label="Permalink to &quot;[`variables/__init__.py`](https://github.com/jasoneri/ComicGUISpider/blob/GUI/variables/__init__.py)&quot;">​</a></h4><ol><li><code>SPIDERS</code> - 爬虫名字：加入新序号(方面下面理解设为序号<code>3</code>²)，值为爬虫名字<code>wnacg</code></li><li><code>DEFAULT_COMPLETER</code> - 默认预设：序号必须，值可空列表。用户配置会覆盖，但是可以先把做了开发的映射放进去</li><li><code>STATUS_TIP</code> - 状态栏输入提示：序号必须，值可空字符串。鼠标悬停在搜索框时，最下状态栏会出现的文字</li></ol><div class="tip custom-block github-alert"><p class="custom-block-title">如目标网站为🔞的</p><p>还需在<code>SPECIAL_WEBSITES</code>加进 爬虫名字<code>wnacg</code> （此处影响存储位置）<br> 在<code>SPECIAL_WEBSITES_IDXES</code>加进 序号<code>3</code>² （此处影响gui逻辑）</p></div><h3 id="_3-ui-代码" tabindex="-1">3. ui 代码 <a class="header-anchor" href="#_3-ui-代码" aria-label="Permalink to &quot;3. ui 代码&quot;">​</a></h3><h4 id="gui-mainwindow-py" tabindex="-1"><a href="https://github.com/jasoneri/ComicGUISpider/blob/GUI/GUI/mainwindow.py" target="_blank" rel="noreferrer"><code>GUI/mainwindow.py</code></a> <a class="header-anchor" href="#gui-mainwindow-py" aria-label="Permalink to &quot;[`GUI/mainwindow.py`](https://github.com/jasoneri/ComicGUISpider/blob/GUI/GUI/mainwindow.py)&quot;">​</a></h4><p>在 setupUi 里加入如下类似代码（需参考 <code>variables/__init__.py</code> 的 <code>SPIDERS</code> 避免使用重复序号导致覆盖）</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">self</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.chooseBox.addItem(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">self</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.chooseBox.setItemText(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, _translate(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;MainWindow&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;3、wnacg🔞&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 🔞标识符不影响任何代码</span></span></code></pre></div><hr><h3 id="_4-无gui测试" tabindex="-1">4. 无GUI测试 <a class="header-anchor" href="#_4-无gui测试" aria-label="Permalink to &quot;4. 无GUI测试&quot;">​</a></h3><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python crawl_only.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">w </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">k 首页 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">i </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span></code></pre></div><h3 id="_5-gui测试" tabindex="-1">5. GUI测试 <a class="header-anchor" href="#_5-gui测试" aria-label="Permalink to &quot;5. GUI测试&quot;">​</a></h3><p><code>python CGS.py</code>，对进行开发的网站测试流程是否正常，然后测试其他网站有没受影响</p><blockquote><p>注意: 当<code>ComicSpider/settings.py</code>里的<code>LOG_FILE</code>不为空时，控制台不会打印任何信息，只会在日志<code>log/scrapy.log</code>中输出，无论什么日志等级<br> 反之想让控制台输出时将其值置为空，在commit时需要改回来</p></blockquote>',34),r=[o];function l(n,h,d,p,c,k){return e(),i("div",null,r)}const _=a(t,[["render",l]]);export{u as __pageData,_ as default};
